          </div>

          <div className="flex items-center gap-4">
             {/* NOTES BUTTON */}
             <button
               onClick={() => setIsNotesOpen(true)}
               className={`flex items-center gap-2 px-3 py-1.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all border ${
