             {/* GLOBAL ACTIONS BASED ON MODE */}
             {appMode === 'json' && smartBlocks.length > 0 && (
                <button onClick={handleExportJSON} className="flex items-center gap-2 px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-xs font-black uppercase tracking-widest shadow-lg shadow-indigo-100 transition-all active:scale-95">
                  <DocumentArrowDownIcon className="w-4 h-4" />
