                                      {block.type === 't' ? t.smart.t : block.type === 'q' ? t.smart.q : t.smart.x}
                                    </span>
                                    <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <button onClick={() => setEditingBlockId(block.id)} className="p-1 text-gray-300 hover:text-indigo-600"><ArrowsPointingOutIcon className="w-3.5 h-3.5" /></button>
                                        <button onClick={() => setSmartBlocks(prev => prev.filter(b => b.id !== block.id))} className="p-1 text-gray-300 hover:text-red-500 ml-1"><TrashIcon className="w-3 h-3"/></button>
                                    </div>
                                  </div>
                                  <div onClick={() => setEditingBlockId(block.id)} className="w-full bg-gray-50 rounded-lg p-2 text-[11px] text-gray-600 line-clamp-2 cursor-pointer hover:bg-gray-100 transition-colors">
                                    {block.text || t.table.empty}
                                  </div>
                                </div>
                              ))
                            )}
                          </div>
                          <div className="grid grid-cols-4 gap-2 pt-2">
                            <button onClick={() => setSmartBlocks(prev => [...prev, {id: crypto.randomUUID(), type:'x', text:''}])} className="col-span-3 py-3 bg-gray-50 hover:bg-gray-100 text-gray-500 rounded-xl text-[9px] font-black uppercase tracking-widest border border-dashed border-gray-200 flex items-center justify-center gap-2 transition-all">
                              <PlusIcon className="w-3.5 h-3.5" /> {t.smart.addBlock}
                            </button>
                            <button onClick={handleClearBlocks} className="col-span-1 py-3 bg-red-50 hover:bg-red-100 text-red-400 hover:text-red-600 rounded-xl text-[9px] font-black uppercase tracking-widest border border-red-100 flex items-center justify-center transition-all">
                              <TrashIcon className="w-4 h-4" />
                            </button>
                          </div>
                        </div>
                      )}
                  </div>
                  <div className="p-4 border-t border-gray-100 bg-gray-50 flex-shrink-0 grid grid-cols-2 gap-3">
                     <button onClick={() => setIsPreviewOpen(true)} className="w-full py-3 bg-white hover:bg-indigo-50 text-indigo-600 border border-indigo-200 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2"><EyeIcon className="w-4 h-4" /> {t.preview.button}</button>
                     <button onClick={() => setActiveTab('basics')} className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2"><CodeBracketIcon className="w-4 h-4" /> {t.smart.generateTable}</button>
                  </div>
                </>
              ) : (
                <>
                  <div className="flex border-b border-gray-200 bg-gray-50/50 flex-shrink-0">
                      <div className="flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 text-indigo-600 bg-white border-b-2 border-indigo-600">
                        <PlusIcon className="w-3.5 h-3.5" /> {t.tabs.csvForm}
                      </div>
                  </div>
                  <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-6">
                      <MetadataForm metadata={csvMetadata} onChange={handleCsvMetadataChange} disabled={false} />
                      <ManualEntryForm onSubmit={handleCsvRowSubmit} />
                  </div>
                </>
              )}
            </div>
          </div>

          {/* RIGHT COLUMN - PREVIEWS & OUTPUTS */}
          <div className="lg:col-span-8 h-full">
            {appMode === 'json' ? (
              activeTab === 'smart' ? (
                <SmartSplitter 
                  key={`smart-${resetKey}`} 
                  onBlocksUpdate={setSmartBlocks} 
                  blocks={smartBlocks} 
                  uiLanguage={uiLanguage} 
                  text={smartEditorText} 
                  onTextChange={setSmartEditorText} 
                />
              ) : <JsonPreview basics={basics} blocks={smartBlocks} uiLanguage={uiLanguage} />
            ) : (
              <TablePreview 
                data={csvTableData} 
                columns={csvHeaders} 
                onMoveColumn={handleMoveColumn} 
                onDeleteColumn={handleDeleteColumn} 
                onClear={handleClearCsvTable} 
                uiLanguage={uiLanguage} 
              />
            )}
          </div>
        </div>
      </main>

      <NotesModal isOpen={isNotesOpen} onClose={() => setIsNotesOpen(false)} currentNote={currentNote} onNoteChange={setCurrentNote} noteHistory={noteHistory} onUpdateHistoryNote={updateHistoryNote} onDeleteHistoryNote={deleteHistoryNote} onClearHistory={clearHistory} uiLanguage={uiLanguage} />
      {isPreviewOpen && <LessonPreviewModal blocks={smartBlocks} basics={basics} uiLanguage={uiLanguage} onClose={() => setIsPreviewOpen(false)} onUpdateBlock={(id, text) => setSmartBlocks(prev => prev.map(b => b.id === id ? {...b, text} : b))} />}

      {editingBlockId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-6 border-b border-gray-100 flex items-center justify-between">
              <h3 className="text-lg font-black text-gray-900 uppercase tracking-tight">{t.smart.modalTitle}</h3>
              <button onClick={() => setEditingBlockId(null)} className="p-2 hover:bg-red-50 text-gray-400 hover:text-red-500 rounded-xl transition-all"><XMarkIcon className="w-6 h-6" /></button>
            </div>
            <div className="flex-1 p-8">
              <textarea 
                autoFocus 
                className="w-full h-full min-h-[400px] text-2xl font-medium leading-relaxed border-none focus:ring-0 resize-none custom-scrollbar"
                value={smartBlocks.find(b => b.id === editingBlockId)?.text || ''}
                onChange={(e) => setSmartBlocks(prev => prev.map(b => b.id === editingBlockId ? {...b, text: e.target.value} : b))}
              />
            </div>
            <div className="p-6 border-t border-gray-100 flex justify-end">
              <button onClick={() => setEditingBlockId(null)} className="px-8 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black uppercase tracking-widest transition-all">
                {t.smart.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { CSVRow } from "../types";

const JSON_SYSTEM_INSTRUCTION = `
You are an expert OCR and Data Extraction specialist.
Your goal is to extract the content of a study guide page as a sequence of distinct blocks for a JSON structure.
RULES:
1. **Atomic Extraction**: Do NOT merge separate paragraphs.
2. **Sequence**: Maintain exact top-to-bottom order.
3. **Classification**: 'title', 'text', or 'question'.
`;

const CSV_SYSTEM_INSTRUCTION = `
You are an expert OCR specialist. Your goal is to map the content of a study guide page into a specific CSV structure.
STRUCTURE:
- text_1, text_2, text_3: Initial reading/intro paragraphs.
- question_1: The first major question or exercise.
- text_4: Text between question 1 and 2.
- question_2: The second major question.
- text_5: Text between question 2 and 3.
- question_3: The third major question.
- text_6: Text between question 3 and 4.
- question_4: The fourth major question.
- text_7, text_8: Final concluding paragraphs.

If a field is not found, leave it empty. Ensure questions and texts are separated according to the flow of the page.
`;

const jsonResponseSchema = {
  type: Type.OBJECT,
  properties: {
    blocks: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING, description: "title, text, question" },
          content: { type: Type.STRING, description: "The text content." }
        },
        required: ["type", "content"],
      },
    },
  },
};

const csvResponseSchema = {
  type: Type.OBJECT,
  properties: {
    lesson_title: { type: Type.STRING },
    text_1: { type: Type.STRING },
    text_2: { type: Type.STRING },
    text_3: { type: Type.STRING },
    question_1: { type: Type.STRING },
    text_4: { type: Type.STRING },
    question_2: { type: Type.STRING },
    text_5: { type: Type.STRING },
    question_3: { type: Type.STRING },
    text_6: { type: Type.STRING },
    question_4: { type: Type.STRING },
    text_7: { type: Type.STRING },
    text_8: { type: Type.STRING },
  },
};

export interface ExtractedBlock {
  type: 'title' | 'text' | 'question';
  content: string;
}

export const processImageWithGemini = async (
  base64Image: string, 
  signal?: AbortSignal,
  onProgress?: (percentage: number) => void
): Promise<ExtractedBlock[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });
  const result = await ai.models.generateContentStream({
    model: "gemini-3-flash-preview", 
    contents: [{ role: "user", parts: [{ inlineData: { mimeType: "image/jpeg", data: base64Image } }, { text: "Extract content as blocks." }] }],
    config: { systemInstruction: JSON_SYSTEM_INSTRUCTION, responseMimeType: "application/json", responseSchema: jsonResponseSchema },
  });

  let fullText = '';
  for await (const chunk of result) {
    if (signal?.aborted) throw new DOMException("Aborted", "AbortError");
    fullText += chunk.text;
    onProgress?.(50); // Simplified for brevety
  }
  return JSON.parse(fullText).blocks || [];
};

export const processImageForCSVTable = async (
  base64Image: string,
  signal?: AbortSignal,
  onProgress?: (percentage: number) => void
): Promise<Partial<CSVRow>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });
  onProgress?.(10);

  const result = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [{
      role: "user",
      parts: [
        { inlineData: { mimeType: "image/jpeg", data: base64Image } },
        { text: "Map this page to the fixed CSV structure. Identify the lesson title and distribute all texts and questions into the numbered slots (text_1 to text_8, question_1 to question_4)." }
      ]
    }],
    config: {
      systemInstruction: CSV_SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: csvResponseSchema,
    },
  });

  onProgress?.(100);
  return JSON.parse(result.text);
};

